'use strict';

/**
 * Sliding window rate limiting middleware for Express.js.
 *
 * This is a TRUE sliding window: every individual request timestamp is stored,
 * and on each incoming request we discard timestamps older than `windowMs`
 * relative to *now*. There is no fixed bucket that resets on a clock boundary,
 * so a client cannot burst 2x the limit across a reset edge.
 *
 * @param {Object} [options]
 * @param {number} [options.windowMs=60000] Window size in milliseconds.
 * @param {number} [options.maxRequests=100] Max allowed requests per window.
 * @param {number} [options.cleanupIntervalMs=60000] How often the janitor runs.
 * @param {(req) => string} [options.keyGenerator] Derive the client key (default req.ip).
 * @returns {Function & { close: () => void }} Express middleware with a close() method.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupIntervalMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]> — each value is a sorted array of request timestamps (ms).
  const hits = new Map();

  function middleware(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    // Pull the existing timestamps and prune everything outside the sliding window.
    const timestamps = hits.get(key) || [];

    // Timestamps are appended in chronological order, so the live entries are a
    // contiguous tail. Find the first index still inside the window and slice once.
    let firstValid = 0;
    while (firstValid < timestamps.length && timestamps[firstValid] <= windowStart) {
      firstValid++;
    }
    const recent = firstValid > 0 ? timestamps.slice(firstValid) : timestamps;

    if (recent.length >= maxRequests) {
      // Over the limit: the window frees up when the OLDEST in-window request ages out.
      const oldest = recent[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      // Persist the pruned list so we don't keep stale entries around.
      hits.set(key, recent);

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      // Reject WITHOUT calling next().
      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return;
    }

    // Under the limit: record this request and allow it through.
    recent.push(now);
    hits.set(key, recent);

    const remaining = maxRequests - recent.length;
    // Window resets (one slot frees) when the oldest in-window request expires.
    const resetMs = recent[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', Math.max(0, remaining));
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  }

  // ---- Memory management -------------------------------------------------
  // Periodically drop keys whose every timestamp has aged out of the window.
  // Without this, idle clients leak Map entries forever.
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      // Last timestamp is the most recent; if even that is stale, the whole entry is dead.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        hits.delete(key);
      }
    }
  }, cleanupIntervalMs);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  // Allow callers to fully stop the timer (e.g. in tests or graceful shutdown).
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
```

