/**
 * rateLimiter.js
 *
 * True sliding-window rate-limiting middleware for Express.js.
 *
 * Unlike a fixed-window counter (which resets on a clock boundary), this
 * implementation stores the exact timestamp of every request for each client
 * IP.  On every incoming request it discards stale timestamps and counts what
 * remains, so the window always trails the *current moment* rather than
 * snapping to a fixed grid.
 *
 * ─── Proxy note ──────────────────────────────────────────────────────────────
 * `req.ip` is taken from Express, which reads `X-Forwarded-For` ONLY when
 * `app.set('trust proxy', true)` (or a hop-count number) is configured.
 * Without that setting, Express uses the raw socket address, so every client
 * behind Nginx / a load balancer appears to share one IP and the limiter will
 * fire way too early.  Enable trust-proxy BEFORE mounting this middleware when
 * your app sits behind any proxy tier.
 * ─────────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window size in milliseconds.
 * @property {number} [maxRequests=100]  - Max requests allowed within that window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {Function} middleware - Express middleware: (req, res, next) => void
 * @property {Function} close      - Clears the background cleanup timer.
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * @param   {RateLimiterOptions} [options={}]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs = (
    typeof options.windowMs === 'number' && options.windowMs > 0
      ? options.windowMs
      : 60_000          // default: 1 minute
  );

  const maxRequests = (
    typeof options.maxRequests === 'number' && options.maxRequests > 0
      ? options.maxRequests
      : 100
  );

  /**
   * Per-IP timestamp store.
   *   key   → client IP string
   *   value → number[]  (Unix-ms timestamps, appended in chronological order)
   *
   * @type {Map<string, number[]>}
   */
  const store = new Map();

  // ── Background cleanup ──────────────────────────────────────────────────
  // Every 60 s, evict IPs whose most-recent request is older than `windowMs`.
  // This bounds memory growth for apps that serve many short-lived clients.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      // Timestamps are in ascending order; the last element is the newest.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] < cutoff) {
        store.delete(ip);
      }
    }
  }, 60_000);

  // Prevent the timer from keeping the Node.js process alive on its own.
  if (cleanupInterval.unref) {
    cleanupInterval.unref();
  }

  // ── Middleware ──────────────────────────────────────────────────────────
  function middleware(req, res, next) {
    const ip  = req.ip || req.socket?.remoteAddress || 'unknown';
    const now = Date.now();

    // 1. Fetch (or initialise) the timestamp log for this IP.
    let timestamps = store.get(ip);
    if (!timestamps) {
      timestamps = [];
      store.set(ip, timestamps);
    }

    // 2. Evict timestamps outside the current window.
    //    Timestamps are stored in ascending order so we binary-search for the
    //    cutoff — O(log n) find + O(k) splice rather than a full linear scan.
    const cutoff = now - windowMs;
    let lo = 0, hi = timestamps.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      if (timestamps[mid] <= cutoff) lo = mid + 1;
      else hi = mid;
    }
    if (lo > 0) timestamps.splice(0, lo);   // remove lo expired entries

    const currentCount = timestamps.length; // valid in-window request count

    // 3. Derive header/response values.
    //    Reset = moment the *oldest* in-window request falls out of the window.
    //    If the window is currently empty the reset is `windowMs` from now.
    const resetMs    = timestamps.length > 0
      ? timestamps[0] + windowMs
      : now + windowMs;
    const resetEpoch = Math.ceil(resetMs / 1000); // seconds since Unix epoch

    // 4. Over limit → reject without calling next().
    if (currentCount >= maxRequests) {
      const retryAfterSec = Math.ceil((resetMs - now) / 1000);

      res.set('Retry-After', String(retryAfterSec));

      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // 5. Under limit → record request, set informational headers, continue.
    timestamps.push(now);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(maxRequests - timestamps.length),
      'X-RateLimit-Reset':     String(resetEpoch),
    });

    return next();
  }

  return {
    middleware,
    /** Call during graceful shutdown or in test teardown hooks. */
    close() {
      clearInterval(cleanupInterval);
    },
  };
}

module.exports = { createRateLimiter };
